#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "ssa.h"
#include "basic-block.h"
#include "dumpfile.h"

namespace {

const pass_data pass_data_count_blocks =
{
  GIMPLE_PASS,       /* type */
  "count_blocks",    /* name */
  OPTGROUP_NONE,     /* optinfo_flags */
  TV_NONE,           /* tv_id */
  PROP_cfg | PROP_ssa, /* properties_required */
  0,                 /* properties_provided */
  0,                 /* properties_destroyed */
  0,                 /* todo_flags_start */
  0,                 /* todo_flags_finish */
};

class pass_count_blocks : public gimple_opt_pass
{
public:
  pass_count_blocks (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_blocks, ctxt)
  {
  }

  /* opt_pass methods: */
  bool gate (function *) final override { return true; }

  unsigned int execute (function *func) final override
  {
    return count_basic_blocks (func);
  }

private:
  unsigned int count_basic_blocks (function *func)
  {
    basic_block bb;
    int block_count = 0;

    /* Count all basic blocks in the function */
    FOR_EACH_BB_FN (bb, func)
      {
        block_count++;
      }

    /* Output statistics to dump file */
    if (dump_file && (dump_flags & TDF_DETAILS))
      {
        fprintf (dump_file,
                 "Function %s: %d basic blocks\n",
                 function_name (func),
                 block_count);
      }

    return 0;
  }
};

} // anon namespace

gimple_opt_pass *
make_pass_count_blocks (gcc::context *ctxt)
{
  return new pass_count_blocks (ctxt);
}

